class Solution:
    def minOperations(self, nums):
        n = len(nums)

        def spf(x):
            if x % 2 == 0:
                return 2
            i = 3
            while i * i <= x:
                if x % i == 0:
                    return i
                i += 2
            return x

        best = None
        for mask in range(1 << n):
            arr = []
            ops = 0
            for i in range(n):
                if mask & (1 << i):
                    arr.append(spf(nums[i]))
                    ops += 1
                else:
                    arr.append(nums[i])
            ok = all(arr[i] <= arr[i + 1] for i in range(n - 1))
            if ok and (best is None or ops < best):
                best = ops
        return best if best is not None else -1

