class Solution:
    def minOperations(self, nums: List[int]) -> int:
        def spf(x):
            if x % 2 == 0:
                return 2
            i = 3
            while i * i <= x:
                if x % i == 0:
                    return i
                i += 2
            return x

        n = len(nums)
        ceiling = nums[-1]
        count = 0
        for i in range(n - 2, -1, -1):
            if nums[i] <= ceiling:
                ceiling = nums[i]
            else:
                p = spf(nums[i])
                if p <= ceiling:
                    count += 1
                    ceiling = p
                else:
                    return -1
        return count

