var minOperations = function(nums) {
    const spf = (x) => {
        if (x % 2 === 0) return 2;
        for (let i = 3; i * i <= x; i += 2) {
            if (x % i === 0) return i;
        }
        return x;
    };
    const n = nums.length;
    let ceiling = nums[n - 1];
    let count = 0;
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] <= ceiling) {
            ceiling = nums[i];
        } else {
            const p = spf(nums[i]);
            if (p <= ceiling) {
                count++;
                ceiling = p;
            } else {
                return -1;
            }
        }
    }
    return count;
};
